        if (existing != null)
        {
            foreach (var action in actions)
                existing.GrantAction(action);
        }
        else
        {
            var permission = new Permission { Resource = resource };
            foreach (var action in actions)
                permission.GrantAction(action);
            Permissions.Add(permission);
        }
    }

    public void AddTimedPermission(string resource, DateTime expiresAt, params string[] actions)
    {
        var permission = new Permission { Resource = resource, ExpiresAt = expiresAt };
        foreach (var action in actions)
            permission.GrantAction(action);
        Permissions.Add(permission);
    }

    public bool IsAuthorized(string resource, string action)
    {
        foreach (var permission in Permissions)
        {
            if (permission.Resource == resource && permission.HasAction(action))
                return true;
        }
        return false;
    }

    public void RevokePermission(string resource)
    {
        Permissions.RemoveAll(p => p.Resource == resource);
    }

    public void CleanExpired()
    {
        Permissions.RemoveAll(p => p.IsExpired());
    }

    public List<string> GetAuthorizedResources()
    {
        var resources = new List<string>();
        foreach (var permission in Permissions)
        {
            if (!permission.IsExpired())
                resources.Add(permission.Resource);
        }
        return resources;
    }

    public override string ToString()
    {
        return $"PermissionSet(Role={Role}, Permissions={Permissions.Count})";
    }
}

